import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';

/**
 * @returns {number[][]}
 */
function emptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

/**
 * @param {number[][]} grid
 * @returns {number[][]}
 */
function cloneGrid(grid) {
	return grid.map((row) => [...row]);
}

const puzzleGrid = emptyGrid();

/** @type {ReturnType<typeof createGame>} */
let gameInstance = createGame({ sudoku: createSudoku(cloneGrid(puzzleGrid)) });

const gridWritable = writable(cloneGrid(puzzleGrid));

const userGridInner = writable(cloneGrid(gameInstance.getSudoku().getGrid()));

/** 撤销是否可用（供 UI 禁用按钮） */
export const canUndoGame = writable(false);

/** 重做是否可用 */
export const canRedoGame = writable(false);

/**
 * 将领域 Game 的当前局面同步到可订阅的 userGrid，并更新撤销/重做可用状态。
 *
 * @returns {void}
 */
function syncUserGridFromDomain() {
	const g = gameInstance.getSudoku().getGrid();
	userGridInner.set(cloneGrid(g));
	canUndoGame.set(gameInstance.canUndo());
	canRedoGame.set(gameInstance.canRedo());
}

/**
 * 用新题目启动一局：更新 puzzle store、重建 Game、同步 UI。
 *
 * @param {number[][]} puzzle
 * @returns {void}
 */
function bootstrapNewPuzzle(puzzle) {
	gridWritable.set(cloneGrid(puzzle));
	gameInstance = createGame({ sudoku: createSudoku(cloneGrid(puzzle)) });
	syncUserGridFromDomain();
}

function createGrid() {
	return {
		subscribe: gridWritable.subscribe,

		/**
		 * @param {('veryeasy' | 'easy' | 'medium' | 'hard')} difficulty
		 * @returns {void}
		 */
		generate(difficulty) {
			bootstrapNewPuzzle(generateSudoku(difficulty));
		},

		/**
		 * @param {string} sencode
		 * @returns {void}
		 */
		decodeSencode(sencode) {
			bootstrapNewPuzzle(decodeSencode(sencode));
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

function createUserGrid() {
	return {
		subscribe: userGridInner.subscribe,

		/**
		 * @param {{ x: number, y: number }} pos
		 * @param {number} value
		 * @returns {void}
		 */
		set: (pos, value) => {
			gameInstance.guess({ row: pos.y, col: pos.x, value });
			syncUserGridFromDomain();
		},

		/**
		 * @param {{ x: number, y: number }} pos
		 * @returns {void}
		 */
		applyHint: (pos) => {
			hints.useHint();
			const current = gameInstance.getSudoku().getGrid();
			const solvedSudoku = solveSudoku(cloneGrid(current));
			gameInstance.guess({ row: pos.y, col: pos.x, value: solvedSudoku[pos.y][pos.x] });
			syncUserGridFromDomain();
		},

		/**
		 * @returns {void}
		 */
		undo: () => {
			gameInstance.undo();
			syncUserGridFromDomain();
		},

		/**
		 * @returns {void}
		 */
		redo: () => {
			gameInstance.redo();
			syncUserGridFromDomain();
		},
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(userGridInner, ($userGrid) => {
	const _invalidCells = [];

	const addInvalid = (x, y) => {
		const xy = x + ',' + y;
		if (!_invalidCells.includes(xy)) _invalidCells.push(xy);
	};

	for (let y = 0; y < SUDOKU_SIZE; y++) {
		for (let x = 0; x < SUDOKU_SIZE; x++) {

			const value = $userGrid[y][x];

			if (value) {
				for (let i = 0; i < SUDOKU_SIZE; i++) {
					// Check the row
					if (i !== x && $userGrid[y][i] === value) {
						addInvalid(x, y);
					}

					// Check the column
					if (i !== y && $userGrid[i][x] === value) {
						addInvalid(x, i);
					}
				}

				// Check the box
				const startY = Math.floor(y / BOX_SIZE) * BOX_SIZE;
				const endY = startY + BOX_SIZE;
				const startX = Math.floor(x / BOX_SIZE) * BOX_SIZE;
				const endX = startX + BOX_SIZE;
				for (let row = startY; row < endY; row++) {
					for (let col = startX; col < endX; col++) {
						if (row !== y && col !== x && $userGrid[row][col] === value) {
							addInvalid(col, row);
						}
					}
				}
			}

		}
	}

	return _invalidCells;
}, []);

syncUserGridFromDomain();
